var FORGE_COLLATE_DESCRIPTION = "Regenerate Forge KB markdown documents from the JSON store. Wraps forge/tools/collate.cjs.";
var FORGE_STORE_DESCRIPTION = "Direct exec of forge/tools/store-cli.cjs. Deterministic CLI, no LLM, no agent loop. store-cli enforces schema validation, status transitions, and path-traversal guards.\n\nCanonical arg shapes (entity \u2208 {sprint, task, bug, feature, event}):\n  write <entity> '<json>'                          \u2014 2 args. ID lives inside json. Do NOT pass id as a separate arg.\n  read <entity> <id> [--json]                       \u2014 2-3 args.\n  list <entity> [key=value ...]                     \u2014 variadic filters.\n  delete <entity> <id>                              \u2014 2 args.\n  update-status <entity> <id> <field> <value> [--force]\n  emit <sprintId> '<json>' [--sidecar]              \u2014 2-3 args. event json embeds eventId, taskId, sprintId.\n  validate <entity> '<json>'                        \u2014 schema check, no write.\n  set-summary <taskId> <phase> [<jsonFile>]         \u2014 phase \u2208 {plan, review_plan, implementation, code_review, validation, triage, approve}. Omit jsonFile: sidecar auto-resolved from record.path.\n  set-bug-summary <bugId> <phase> [<jsonFile>]      \u2014 omit jsonFile: sidecar auto-resolved from record.path.\n  progress <sprintOrBugId> <agentName> <bannerKey> <status> [detail]\n  progress-clear <sprintOrBugId>\n  describe <entity>                                 \u2014 print JSON Schema.\n  template <entity>                                 \u2014 print canonical sample (call this BEFORE write to get the shape).\n\nCommon mistake: 'write sprint <id> <json>' (3-arg) FAILS \u2014 id is parsed as JSON. Use 'write sprint <json>' (2-arg).";
var FORGE_COMMIT_DESCRIPTION = "Direct exec of forge/tools/commit-task.cjs \u2014 the deterministic commit choreography (forge-engineering#40). ONE call owns: preflight gate, status precondition (task 'approved' / bug 'in-progress'), staging-set derivation (record artifact dir + summaries.implementation.files_changed provenance + 'also' extras; gitignored paths warn-skipped), commit-boundary guard (aborts on a pre-staged index), git commit, and the terminal status transition (task\u2192committed / bug\u2192fixed).\n\nSuccess JSON: {ok:true, committed:true, sha, staged[]} \u2014 or the no-op success {ok:true, committed:false, reason:'nothing-to-commit'} when the staging set is already clean (e.g. the fix was at HEAD): the record is STILL sealed; do not improvise staging.\n\nNever run git add / git commit / git reset yourself in the commit phase.";
var FORGE_VALIDATE_STORE_DESCRIPTION = "Validate Forge store integrity \u2014 wraps forge/tools/validate-store.cjs. Exit code 1 means validation errors were found (returned as informational content, not isError). Only hard failures (ENOENT, timeout) return isError: true.";
var FORGE_CONFIG_DESCRIPTION = "Read/write .forge/config.json \u2014 wraps forge/tools/manage-config.cjs. Supported subcommands: get, set, list-pipelines, pipeline, resolve-forge-root.";
var FORGE_STORE_DESCRIBE_DESCRIPTION = "Return the raw JSON Schema for a Forge store entity. Wraps `store-cli.cjs describe <entity>`. Call this BEFORE writing a record so you know the exact required fields, types, enums, and constraints.";
var FORGE_STORE_TEMPLATE_DESCRIPTION = "Return a canonical sample record for a Forge store entity, with all required fields populated with placeholder values that match the schema (enum first-value, ISO date-time, ID placeholders, etc.). Wraps `store-cli.cjs template <entity>`. Use this BEFORE writing a record to avoid validation failures.";
var FORGE_STORE_QUERY_DESCRIPTION = "Search / find / query the Forge store. Wraps `store-cli.cjs` query/nlp/schema dispatch (which delegates to store-query.cjs). Use `nlp` for natural-language intent (e.g. 'open bugs in S12', 'blocked tasks'); `query` with flag args for structured filters (--sprint, --task, --bug, --feature, --status, --keyword, --with-blockers, --with-blocked-tasks, --with-sprint, --with-feature, --no-excerpts, --list-sprints, --mode auto|strict|off); `schema` for the project schema and grammar reference (entity ID patterns, status enums, FKs, synonyms).";
var FORGE_VERIFY_APPLY_DESCRIPTION = "Verify file modifications actually landed on disk. Call AFTER applying enhancement edits, BEFORE invoking manage-versions add-snapshot. Detects hallucinated Edit-tool calls (e.g. when old_string didn't match exactly and the Edit silently no-op'd). Returns structured results: `modified` (verified \u2014 change is on disk), `unchanged` (agent claim was wrong \u2014 re-apply needed), `untracked` (no manifest entry \u2014 ambiguous, treat as potentially modified), `missing` (file gone). If `unchanged.length > 0`, RE-APPLY those edits via Edit/Write and call this tool again until empty.";
var FORGE_ARTIFACT_DESCRIPTION = "Read, write, or list phase artifacts (PLAN.md, PROGRESS.md, *-SUMMARY.json, etc.) for a task, bug, or sprint. Resolves paths automatically from entity ID \u2014 never construct artifact paths manually.\n\n(artifact list loaded at runtime).\n\nReading: a whole-file `read` returns a COMPRESSED, lossy map (may omit body lines) \u2014 cheap for a gist. For exact text, read by SECTION: command 'outline' returns the heading map, then 'read' with `section` set to a heading returns that section's EXACT, uncompressed source. Prefer outline\u2192section over a whole `read` when you need precise or partial content (and to avoid re-reading the same artifact). (Section/outline apply to markdown artifacts only, not JSON *-summary.)\n\nJSON summary artifacts are validated on write (objective, key_changes, verdict, written_at required). Use 'list' to see which artifacts already exist for an entity.";
var FORGE_PREFLIGHT_DESCRIPTION = "Run the pre-flight gate check for a phase. Wraps forge/tools/preflight-gate.cjs. Returns exit 0 if the phase is safe to proceed, exit 1 with a reason if blocked.";
var FORGE_BANNER_DESCRIPTION = "Display a decorative phase banner. Wraps forge/tools/banners.cjs. Available banners: ember, tide, oracle, rift, bloom, north, lumen, forge, drift, void, entelligentsia.";
var FORGE_MARKDOWN_DESCRIPTION = "Structural access to a Markdown file via its AST \u2014 read STRUCTURE instead of the whole file. Operations: `outline` (heading tree + section line ranges \u2014 a compact doc map; read this first for a long KB doc, then `section` the part you need); `section` (exact source of one heading's section, requires `heading`); `tables` (GFM tables as header+rows JSON); `frontmatter` (YAML frontmatter as JSON); `ast` (compact structural tree as JSON). Use for KB docs, INDEX/registry tables, sprint briefs, retros, and memory frontmatter rather than reading or regex-parsing flat markdown. All operations return EXACT, uncompressed output (unlike forge_artifact's whole-file read, which compresses).";
var FORGE_ASK_USER_DESCRIPTION = "forge:ask_user \u2014 Present an interactive prompt to the user and return their answer. Accepts three input types: 'confirm' (Y/N), 'choice' (select from a list), or 'text' (free-form single-line input). Blocks the model loop until the user responds. In non-interactive mode (FORGE_YES=1 or --non-interactive), returns the default immediately.";
